const CHINESE_YIN_YANG = {yin:{label:"Yin (阴)",desc:"Receptive, introspective, and yielding. Yin energy processes internally before acting. You absorb before you respond, and your power comes from depth rather than display."},yang:{label:"Yang (阳)",desc:"Active, expressive, and initiating. Yang energy moves first and reflects later. You project outward naturally, and your power comes from action and visibility."}};

function getChineseZodiac(birthDate, birthTime) {
  if (!birthDate) return null;
  const parts = birthDate.split(/[-\/]/);
  let year, month, day;
  if (parts[0].length === 4) { year = parseInt(parts[0]); month = parseInt(parts[1]); day = parseInt(parts[2]); }
  else { month = parseInt(parts[0]); day = parseInt(parts[1]); year = parseInt(parts[2]); }
  if (isNaN(year)) return null;
  // Approximate Chinese New Year (varies between Jan 21 - Feb 20)
  // Use Feb 4 as rough cutoff (Start of Spring / Lichun)
  const adjustedYear = (month < 2 || (month === 2 && day < 4)) ? year - 1 : year;
  const animalIdx = (adjustedYear - 4) % 12;
  const animal = CHINESE_ANIMALS[animalIdx >= 0 ? animalIdx : animalIdx + 12];
  const elementIdx = (adjustedYear - 4) % 10;
  const element = CHINESE_ELEMENTS_CYCLE[elementIdx >= 0 ? elementIdx : elementIdx + 10];
  const polarity = adjustedYear % 2 === 0 ? "yang" : "yin";
  // Heavenly Stem
  const stems = ["Jia","Yi","Bing","Ding","Wu","Ji","Geng","Xin","Ren","Gui"];
  const stemIdx = (adjustedYear - 4) % 10;
  const stem = stems[stemIdx >= 0 ? stemIdx : stemIdx + 10];
  // Earthly Branch
  const branches = ["Zi","Chou","Yin","Mao","Chen","Si","Wu","Wei","Shen","You","Xu","Hai"];
  const branch = branches[animalIdx >= 0 ? animalIdx : animalIdx + 12];
  // Fixed element of animal (natural element)
  const animalElements = {Rat:"Water",Ox:"Earth",Tiger:"Wood",Rabbit:"Wood",Dragon:"Earth",Snake:"Fire",Horse:"Fire",Goat:"Earth",Monkey:"Metal",Rooster:"Metal",Dog:"Earth",Pig:"Water"};
  const fixedElement = animalElements[animal];
  // Approximate month animal (Chinese solar months)
  const monthAnimals = ["Ox","Tiger","Rabbit","Dragon","Snake","Horse","Goat","Monkey","Rooster","Dog","Pig","Rat"];
  const monthAnimal = monthAnimals[month - 1] || "Rat";
  // Day animal (simplified)
  const dayNum = Math.floor(new Date(year, month-1, day).getTime() / 86400000);
  const dayAnimal = CHINESE_ANIMALS[((dayNum % 12) + 12) % 12];
  // Hour animal (if birth time available)
  let hourAnimal = null;
  if (birthTime && typeof birthTime === "string" && birthTime.includes(":")) {
    const hh = parseInt(birthTime.split(":")[0]);
    if (!isNaN(hh)) {
      // Chinese double-hours: Rat 23-01, Ox 01-03, Tiger 03-05, Rabbit 05-07, Dragon 07-09, Snake 09-11, Horse 11-13, Goat 13-15, Monkey 15-17, Rooster 17-19, Dog 19-21, Pig 21-23
      const hourIdx = Math.floor(((hh + 1) % 24) / 2);
      hourAnimal = CHINESE_ANIMALS[hourIdx];
    }
  }
  return { year: adjustedYear, animal, element, polarity, stem, branch, pillar: stem + " " + branch, fixedElement, monthAnimal, dayAnimal, hourAnimal, traits: CHINESE_ANIMAL_TRAITS[animal], elementTraits: CHINESE_ELEMENT_TRAITS[element], yinYang: CHINESE_YIN_YANG[polarity] };
}

const HEAVENLY_STEMS = ['Wood', 'Fire', 'Earth', 'Metal', 'Water'];
const STEM_NAMES = ['甲', '乙', '丙', '丁', '戊', '己', '庚', '辛', '壬', '癸'];
const EARTHLY_BRANCHES = ['鼠', '牛', '虎', '兔', '龍', '蛇', '馬', '羊', '猴', '雞', '狗', '豬'];
const ZODIAC_ANIMALS = ['Rat', 'Ox', 'Tiger', 'Rabbit', 'Dragon', 'Snake', 'Horse', 'Goat', 'Monkey', 'Rooster', 'Dog', 'Pig'];
const ELEMENTS = ['Metal', 'Water', 'Wood', 'Fire', 'Earth'];
const ELEMENT_YIN_YANG = {
  Metal: { yin: 'Yin Metal', yang: 'Yang Metal' },
  Water: { yin: 'Yin Water', yang: 'Yang Water' },
  Wood: { yin: 'Yin Wood', yang: 'Yang Wood' },
  Fire: { yin: 'Yin Fire', yang: 'Yang Fire' },
  Earth: { yin: 'Yin Earth', yang: 'Yang Earth' }
};

function getChineseZodiacAnimal(year) {
  // Rat is 1900
  const baseYear = 1900;
  const index = (year - baseYear) % 12;
  return ZODIAC_ANIMALS[index];
}

function getChineseZodiacElement(year) {
  // Metal cycle starts at 1900
  const baseYear = 1900;
  const index = Math.floor((year - baseYear) / 2) % 5;
  return ELEMENTS[index];
}

function getChineseZodiacPolarity(year) {
  // 1900 is Yang Metal Rat
  const baseYear = 1900;
  const stemIndex = (year - baseYear) % 10;
  return stemIndex % 2 === 0 ? 'Yang' : 'Yin';
}

function getStemBranchForYear(year) {
  const baseYear = 1900; // 1900 is 甲子 (Yang Metal Rat)
  const cycleIndex = (year - baseYear) % 60;
  const stemIndex = cycleIndex % 10;
  const branchIndex = cycleIndex % 12;
  return {
    stem: STEM_NAMES[stemIndex],
    stemName: HEAVENLY_STEMS[Math.floor(stemIndex / 2)],
    branch: EARTHLY_BRANCHES[branchIndex],
    animal: ZODIAC_ANIMALS[branchIndex],
    polarity: stemIndex % 2 === 0 ? 'Yang' : 'Yin'
  };
}

function getStemBranchForMonth(year, month) {
  // Lunar months start from Tiger month (spring)
  // This is a simplified calculation; accurate Bazi requires lunar calendar conversion
  const baseYear = 1900;
  const yearCycle = (year - baseYear) % 60;
  const stemIndex = yearCycle % 10;

  // Month stems follow a fixed pattern relative to year stem
  const monthStemIndex = (stemIndex * 2 + (month - 1)) % 10;

  // Month branches: Tiger(1), Rabbit(2), Dragon(3), Snake(4), Horse(5), Goat(6), Monkey(7), Rooster(8), Dog(9), Pig(10), Rat(11), Ox(12)
  const monthBranchIndex = (month + 1) % 12;

  return {
    stem: STEM_NAMES[monthStemIndex],
    stemName: HEAVENLY_STEMS[Math.floor(monthStemIndex / 2)],
    branch: EARTHLY_BRANCHES[monthBranchIndex],
    animal: ZODIAC_ANIMALS[monthBranchIndex],
    polarity: monthStemIndex % 2 === 0 ? 'Yang' : 'Yin'
  };
}

function getStemBranchForDay(dateStr) {
  // dateStr format: "yyyy-mm-dd"
  // This calculation uses a known reference point
  // January 1, 1900 is day 1 of the Bazi calendar (甲子)
  const baseDate = new Date(1900, 0, 1);
  const currentDate = new Date(dateStr);
  const dayDiff = Math.floor((currentDate - baseDate) / (1000 * 60 * 60 * 24));
  const dayCycle = dayDiff % 60;

  const stemIndex = dayCycle % 10;
  const branchIndex = dayCycle % 12;

  return {
    stem: STEM_NAMES[stemIndex],
    stemName: HEAVENLY_STEMS[Math.floor(stemIndex / 2)],
    branch: EARTHLY_BRANCHES[branchIndex],
    animal: ZODIAC_ANIMALS[branchIndex],
    polarity: stemIndex % 2 === 0 ? 'Yang' : 'Yin'
  };
}

function getStemBranchForHour(timeStr, dayStemIndex) {
  // timeStr format: "HH:MM" (24-hour format)
  if (!timeStr || timeStr.length === 0) {
    return null;
  }

  const hours = parseInt(timeStr.substring(0, 2), 10);

  // Hour branches map to 2-hour periods in 12-hour Chinese system
  // 23:00-00:59 = Rat (hour 0)
  // 01:00-02:59 = Ox (hour 1), etc.
  let hourBranchIndex;
  if (hours >= 23 || hours < 1) {
    hourBranchIndex = 0; // Rat
  } else {
    hourBranchIndex = Math.ceil(hours / 2) % 12;
  }

  // Hour stems follow a fixed pattern relative to day stem
  // Each day stem has a corresponding hour stem sequence
  const hourStemIndex = (dayStemIndex * 2 + hourBranchIndex) % 10;

  return {
    stem: STEM_NAMES[hourStemIndex],
    stemName: HEAVENLY_STEMS[Math.floor(hourStemIndex / 2)],
    branch: EARTHLY_BRANCHES[hourBranchIndex],
    animal: ZODIAC_ANIMALS[hourBranchIndex],
    polarity: hourStemIndex % 2 === 0 ? 'Yang' : 'Yin'
  };
}

function getFourPillars(dateStr, timeStr) {
  // dateStr format: "yyyy-mm-dd"
  const parts = dateStr.split('-');
  const year = parseInt(parts[0], 10);
  const month = parseInt(parts[1], 10);

  const yearPillar = getStemBranchForYear(year);
  const monthPillar = getStemBranchForMonth(year, month);
  const dayPillar = getStemBranchForDay(dateStr);

  const dayStemIndex = (year - 1900) % 10; // Simplified; should use actual day stem
  // Get actual day stem from dayPillar
  const actualDayStemIndex = STEM_NAMES.indexOf(dayPillar.stem);

  const hourPillar = timeStr && timeStr.length > 0 ? getStemBranchForHour(timeStr, actualDayStemIndex) : null;

  return {
    year: yearPillar,
    month: monthPillar,
    day: dayPillar,
    hour: hourPillar
  };
}

function getElementalDistribution(fourPillars) {
  const elementCounts = {
    Metal: 0,
    Water: 0,
    Wood: 0,
    Fire: 0,
    Earth: 0
  };

  const pillars = [fourPillars.year, fourPillars.month, fourPillars.day];
  if (fourPillars.hour) pillars.push(fourPillars.hour);

  pillars.forEach(pillar => {
    const element = pillar.stemName;
    if (elementCounts.hasOwnProperty(element)) {
      elementCounts[element]++;
    }
  });

  return elementCounts;
}

function getChineseZodiacCompatibility(animal1, animal2) {
  const compatibility = {
    Rat: { best: ['Ox', 'Dragon', 'Monkey'], avoid: ['Horse', 'Rabbit', 'Goat', 'Rooster'] },
    Ox: { best: ['Rat', 'Snake', 'Rooster'], avoid: ['Tiger', 'Dragon', 'Horse', 'Sheep', 'Dog'] },
    Tiger: { best: ['Horse', 'Dog', 'Pig'], avoid: ['Monkey', 'Snake', 'Ox'] },
    Rabbit: { best: ['Goat', 'Pig', 'Dog'], avoid: ['Rat', 'Rooster', 'Horse', 'Dragon'] },
    Dragon: { best: ['Rat', 'Monkey', 'Rooster'], avoid: ['Ox', 'Goat', 'Dog', 'Rabbit'] },
    Snake: { best: ['Ox', 'Rooster'], avoid: ['Tiger', 'Pig', 'Monkey'] },
    Horse: { best: ['Tiger', 'Goat', 'Dog'], avoid: ['Rat', 'Ox', 'Rabbit', 'Horse'] },
    Goat: { best: ['Rabbit', 'Horse', 'Pig'], avoid: ['Ox', 'Dragon', 'Dog'] },
    Monkey: { best: ['Rat', 'Dragon', 'Rabbit'], avoid: ['Tiger', 'Snake', 'Pig'] },
    Rooster: { best: ['Ox', 'Snake', 'Dragon'], avoid: ['Rabbit', 'Horse', 'Rat', 'Pig'] },
    Dog: { best: ['Tiger', 'Rabbit', 'Horse'], avoid: ['Dragon', 'Goat', 'Rooster'] },
    Pig: { best: ['Rabbit', 'Goat', 'Tiger'], avoid: ['Snake', 'Monkey', 'Pig'] }
  };

  if (!compatibility[animal1]) return 'Unknown';
  const comp = compatibility[animal1];
  if (comp.best.includes(animal2)) return 'Highly Compatible';
  if (comp.avoid.includes(animal2)) return 'Challenging';
  return 'Neutral';
}

